import ReactCrop, { type Crop, centerCrop, makeAspectCrop } from 'react-image-crop';
import 'react-image-crop/dist/ReactCrop.css';

// Constants
const CONSTANTS = {
    TARGET_SIZE: 1024,
    MAX_RESIZE_WIDTH: 2048,
    WEBP_QUALITY: 0.92,
    JPEG_QUALITY: 0.95,
    DEFAULT_CROP_WIDTH: 80,
} as const;

const SUPPORTED_FORMATS = /\.(jpg|jpeg|png|gif|webp)$/i;

// Optimized styles with better performance
const styles = {
    photoSubText: {
        fontSize: "11px",
        color: "grey",
        textAlign: "center" as const,
        display: "block" as const,
    },
    
    currentPhoto: {
        width: "200px",
        height: "200px",
        objectFit: "cover" as const,
        borderRadius: "8px",
        display: "block" as const,
    },
} as const;

// Utility functions
const supportsWebP = (() => {
    let supported: boolean | null = null;
    return (): boolean => {
        if (supported === null) {
            const canvas = document.createElement('canvas');
            canvas.width = 1;
            canvas.height = 1;
            supported = canvas.toDataURL('image/webp').indexOf('data:image/webp') === 0;
        }
        return supported;
    };
})();

const getOptimalFormat = (originalType: string) => {
    if (supportsWebP()) {
        return {
            format: 'image/webp' as const,
            quality: CONSTANTS.WEBP_QUALITY,
            extension: '.webp',
        };
    }
    
    if (originalType.includes('png')) {
        return {
            format: 'image/png' as const,
            quality: undefined,
            extension: '.png',
        };
    }
    
    return {
        format: 'image/jpeg' as const,
        quality: CONSTANTS.JPEG_QUALITY,
        extension: '.jpg',
    };
};

// Optimized function to convert crop to pixels with high quality
function getCroppedImg(image: HTMLImageElement, crop: Crop, originalFileType: string = 'image/jpeg'): Promise<Blob> {
    const canvas = document.createElement('canvas');
    const ctx = canvas.getContext('2d');
    
    if (!ctx) {
        throw new Error('No 2d context');
    }

    const scaleX = image.naturalWidth / image.width;
    const scaleY = image.naturalHeight / image.height;
    
    // Set canvas size to square for high quality
    canvas.width = CONSTANTS.TARGET_SIZE;
    canvas.height = CONSTANTS.TARGET_SIZE;

    // Enable high-quality image rendering
    ctx.imageSmoothingEnabled = true;
    ctx.imageSmoothingQuality = 'high';

    // Fill with white background for JPEGs to avoid transparency issues
    if (!originalFileType.includes('png')) {
        ctx.fillStyle = '#FFFFFF';
        ctx.fillRect(0, 0, CONSTANTS.TARGET_SIZE, CONSTANTS.TARGET_SIZE);
    }

    ctx.drawImage(
        image,
        crop.x * scaleX,
        crop.y * scaleY,
        crop.width * scaleX,
        crop.height * scaleY,
        0,
        0,
        CONSTANTS.TARGET_SIZE,
        CONSTANTS.TARGET_SIZE
    );

    return new Promise((resolve) => {
        const { format, quality } = getOptimalFormat(originalFileType);
        canvas.toBlob((blob) => {
            if (blob) {
                resolve(blob);
            }
        }, format, quality);
    });
}

// Optimized function to resize image if it's too large with high quality preservation
function resizeImage(file: File, maxWidth: number = CONSTANTS.MAX_RESIZE_WIDTH): Promise<File> {
    return new Promise((resolve) => {
        const canvas = document.createElement('canvas');
        const ctx = canvas.getContext('2d');
        const img = new Image();
        
        img.onload = () => {
            const { width, height } = img;
            
            // Only resize if image is larger than maxWidth
            if (width <= maxWidth && height <= maxWidth) {
                resolve(file);
                return;
            }
            
            // Calculate new dimensions maintaining aspect ratio
            const scale = Math.min(maxWidth / width, maxWidth / height);
            canvas.width = width * scale;
            canvas.height = height * scale;
            
            if (ctx) {
                // Enable high-quality image rendering
                ctx.imageSmoothingEnabled = true;
                ctx.imageSmoothingQuality = 'high';
                ctx.drawImage(img, 0, 0, canvas.width, canvas.height);
            }
            
            const { format, quality, extension } = getOptimalFormat(file.type);
            const fileName = file.name.replace(/\.[^/.]+$/, '') + extension;
            
            canvas.toBlob((blob) => {
                if (blob) {
                    const resizedFile = new File([blob], fileName, {
                        type: format,
                        lastModified: Date.now(),
                    });
                    resolve(resizedFile);
                }
            }, format, quality);
        };
        
        img.src = URL.createObjectURL(file);
    });
}

// Memoized photo display component to prevent unnecessary re-renders
const PhotoDisplay = React.memo(({ 
    croppedImgSrc, 
    profilePhoto 
}: {
    croppedImgSrc: string;
    profilePhoto?: string;
}) => {
    const handleImageError = React.useCallback((e: React.SyntheticEvent<HTMLImageElement>) => {
        const target = e.target as HTMLImageElement;
        target.style.display = 'none';
    }, []);

    if (croppedImgSrc) {
        return (
            <Card sx={{ width: 210, height: 210, overflow: 'hidden' }}>
                <CardContent sx={{ p: '5px', width: '100%', height: '100%', display: 'flex', alignItems: 'center', justifyContent: 'center', '&:last-child': { pb: '5px' } }}>
                    <img
                        src={croppedImgSrc}
                        alt="Preview Photo"
                        width={200}
                        height={200}
                        style={{
                            objectFit: "cover",
                            borderRadius: "8px",
                            display: "block"
                        }}
                        onError={handleImageError}
                    />
                </CardContent>
            </Card>
        );
    }

    if (profilePhoto) {
        return (
            <Card sx={{ width: 210, height: 210, overflow: 'hidden' }}>
                <CardContent sx={{ p: '5px', width: '100%', height: '100%', display: 'flex', alignItems: 'center', justifyContent: 'center', '&:last-child': { pb: '5px' } }}>
                    <img
                        src={ResolvePhotoUrl(profilePhoto, true)}
                        alt="Current Profile"
                        width={200}
                        height={200}
                        style={{
                            objectFit: "cover",
                            borderRadius: "8px",
                            display: "block"
                        }}
                        onError={handleImageError}
                    />
                </CardContent>
            </Card>
        );
    }

    return (
        <Card sx={{ width: 210, height: 210, overflow: 'hidden' }}>
            <CardContent sx={{ p: '5px', width: '100%', height: '100%', display: 'flex', alignItems: 'center', justifyContent: 'center', '&:last-child': { pb: '5px' } }}>
                <Box sx={{ display: 'flex', flexDirection: 'column', alignItems: 'center', color: 'text.secondary' }}>
                    <Avatar sx={{ width: 80, height: 80, mb: 1, bgcolor: 'grey.300' }}>
                        <PersonIcon sx={{ fontSize: 40 }} />
                    </Avatar>
                    <Typography variant="body2">No photo uploaded</Typography>
                </Box>
            </CardContent>
        </Card>
    );
});

PhotoDisplay.displayName = 'PhotoDisplay';

export const ProfilePhotoUpdate: React.FunctionComponent = () => {
    const { profileState, setProfileState } = useProfilesStore();
    
    // State management - using CallStatus pattern
    const [uploadStatus, setUploadStatus] = React.useState<CallStatus>(CallStatus.NotStarted);
    const [statusMessage, setStatusMessage] = React.useState<string>("");
    const [preparedMessage, setPreparedMessage] = React.useState<string>("");
    const [imgSrc, setImgSrc] = React.useState<string>("");
    const [croppedImgSrc, setCroppedImgSrc] = React.useState<string>("");
    const [crop, setCrop] = React.useState<Crop>();
    const [completedCrop, setCompletedCrop] = React.useState<Crop>();
    const [showCropDialog, setShowCropDialog] = React.useState<boolean>(false);
    const [isProcessing, setIsProcessing] = React.useState<boolean>(false);
    const [originalFileType, setOriginalFileType] = React.useState<string>('image/jpeg');
    
    const imgRef = React.useRef<HTMLImageElement>(null);
    const hasFetchedRef = React.useRef<boolean>(false);
    
    // Display name for file (computed from processing state)
    const displayName = React.useMemo(() => {
        if (isProcessing) return "Processing...";
        if (preparedMessage) return "Ready to upload";
        return "";
    }, [isProcessing, preparedMessage]);

    // Load profile data if not available
    React.useEffect(() => {
        if (!profileState.data.id && !hasFetchedRef.current) {
            hasFetchedRef.current = true;
            ApiGlobalStateManager(ProfileServices.GetProfile(), setProfileState);
        }
    }, [profileState.data.id]);

    // Cleanup URLs on unmount and when URLs change
    React.useEffect(() => {
        return () => {
            if (imgSrc) URL.revokeObjectURL(imgSrc);
            if (croppedImgSrc) URL.revokeObjectURL(croppedImgSrc);
        };
    }, [imgSrc, croppedImgSrc]);

    const handleImageChange = React.useCallback(async (event: React.ChangeEvent<HTMLInputElement>) => {
        setStatusMessage("");
        setUploadStatus(CallStatus.NotStarted);
        setPreparedMessage("");
        
        // Clean up any existing cropped image URL
        if (croppedImgSrc) {
            URL.revokeObjectURL(croppedImgSrc);
            setCroppedImgSrc("");
        }
        
        const file = event.target.files?.[0];
        
        if (!file) return;
        
        if (!SUPPORTED_FORMATS.test(file.name)) {
            setStatusMessage("Please select valid image file (jpg, jpeg, png, gif, webp)");
            setUploadStatus(CallStatus.Failure);
            return;
        }
        
        setIsProcessing(true);
        setUploadStatus(CallStatus.InProgress);
        
        try {
            // Store original file type for quality preservation
            setOriginalFileType(file.type);
            
            // Resize image if too large
            const resizedFile = await resizeImage(file);
            
            // Create image URL for cropping
            const imageUrl = URL.createObjectURL(resizedFile);
            setImgSrc(imageUrl);
            setShowCropDialog(true);
            
            setStatusMessage(`Image loaded. Size: ${(resizedFile.size / 1024).toFixed(1)} KB`);
            setUploadStatus(CallStatus.NotStarted);
        } catch (error) {
            logger.error('ProfilePhotoUpdate', 'Error processing image (load)', error);
            setStatusMessage("Error processing image");
            setUploadStatus(CallStatus.Failure);
        } finally {
            setIsProcessing(false);
        }
    }, [croppedImgSrc]);

    const onImageLoad = React.useCallback((e: React.SyntheticEvent<HTMLImageElement>) => {
        const { width, height } = e.currentTarget;
        
        // Create a square crop in the center
        const crop = centerCrop(
            makeAspectCrop(
                {
                    unit: '%',
                    width: CONSTANTS.DEFAULT_CROP_WIDTH,
                },
                1, // aspect ratio 1:1 for square
                width,
                height
            ),
            width,
            height
        );
        
        setCrop(crop);
        setCompletedCrop(crop);
    }, []);

    const handleCropComplete = React.useCallback(async () => {
        if (!imgRef.current || !completedCrop) {
            setStatusMessage("Please select a crop area");
            setUploadStatus(CallStatus.Failure);
            return;
        }

        setIsProcessing(true);
        setUploadStatus(CallStatus.InProgress);

        try {
            const croppedBlob = await getCroppedImg(imgRef.current, completedCrop, originalFileType);
            const { extension } = getOptimalFormat(originalFileType);
            
            const croppedFile = new File([croppedBlob], 
                `cropped-image${extension}`, {
                type: croppedBlob.type,
                lastModified: Date.now(),
            });

            setShowCropDialog(false);
            
            // Create preview URL for the cropped image
            const croppedPreviewUrl = URL.createObjectURL(croppedBlob);
            setCroppedImgSrc(croppedPreviewUrl);
            
            // Clean up the original image URL
            if (imgSrc) {
                URL.revokeObjectURL(imgSrc);
                setImgSrc("");
            }

            // Auto-upload the cropped image
            setStatusMessage("Uploading your photo...");
            setUploadStatus(CallStatus.InProgress);
            
            const data = new FormData();
            data.append("file", croppedFile);
            
            ProfileServices.UpdateProfilePhoto(data)
                .then(() => {
                    setStatusMessage("Profile photo uploaded successfully!");
                    setUploadStatus(CallStatus.Success);
                    setPreparedMessage("");
                    if (croppedPreviewUrl) {
                        URL.revokeObjectURL(croppedPreviewUrl);
                        setCroppedImgSrc("");
                    }
                    ApiGlobalStateManager(ProfileServices.GetProfile(), setProfileState);
                })
                .catch(() => {
                    setStatusMessage("Failed to upload photo. Please try again.");
                    setUploadStatus(CallStatus.Failure);
                });
            
        } catch (error) {
            logger.error('ProfilePhotoUpdate', 'Error processing image (crop)', error);
            setStatusMessage("Error processing image");
            setUploadStatus(CallStatus.Failure);
        } finally {
            setIsProcessing(false);
        }
    }, [imgRef, completedCrop, originalFileType, imgSrc, setProfileState]);

    const handleCropCancel = React.useCallback(() => {
        setShowCropDialog(false);
        setPreparedMessage("");
        if (imgSrc) {
            URL.revokeObjectURL(imgSrc);
            setImgSrc("");
        }
        if (croppedImgSrc) {
            URL.revokeObjectURL(croppedImgSrc);
            setCroppedImgSrc("");
        }
    }, [imgSrc, croppedImgSrc]);

    return (
        <>
            <PageCard>
                <Box sx={{ display: 'flex', flexDirection: 'column', alignItems: 'center', width: '100%' }}>
                    {/* Upload New Photo */}
                    <SectionHeading sx={{ mb: 2, textAlign: 'center' }}>Upload New Photo</SectionHeading>
                    <Paper
                        component="form"
                        sx={{ 
                            padding: '5px 0px', 
                            display: 'flex', 
                            alignItems: 'center', 
                            width: "100%", 
                            maxWidth: "400px",
                            mb: 2
                        }}
                    >
                    <InputBase
                        sx={{ ml: 1, flex: 1 }}
                        placeholder="Select profile photo"
                        slotProps={{ input: { 'aria-label': 'Profile photo' } }}
                        value={displayName}
                        readOnly
                    />
                    <input
                        accept="image/*"
                        hidden
                        multiple={false}
                        id="photo-upload-input"
                        type="file"
                        onChange={handleImageChange}
                        disabled={isProcessing}
                    />
                    <label htmlFor="photo-upload-input" >
                        <Button 
                            component="span" 
                            sx={{ p: '10px', minWidth: '30px' }}
                            disabled={isProcessing}
                        >
                            <AddAPhotoIcon />
                        </Button>
                    </label>
                </Paper>
                <Box sx={{ textAlign: 'center', mb: 2 }}>
                    <span style={styles.photoSubText}>
                        {preparedMessage || "(Photo will be automatically uploaded after cropping with WebP compression for best quality)"}
                    </span>
                </Box>
                <Box sx={{ textAlign: 'center', mb: 2 }}>
                    <StatusMessage
                        currentStatus={uploadStatus}
                        successMessage={uploadStatus === CallStatus.Success ? statusMessage : undefined}
                        failureMessage={uploadStatus === CallStatus.Failure ? statusMessage : undefined}
                        notStartedMessage={uploadStatus === CallStatus.NotStarted && statusMessage ? statusMessage : undefined}
                        correlationId={undefined}
                    />
                </Box>

                <Divider sx={{ mb: 3 }} />

                {/* Current Photo Display */}
                <SectionHeading sx={{ mb: 2, textAlign: 'center' }}>
                    {croppedImgSrc ? 'Preview Photo' : 'Current Profile Photo'}
                </SectionHeading>
                <Box sx={{ display: 'flex', justifyContent: 'center', mb: 2 }}>
                    <PhotoDisplay 
                        croppedImgSrc={croppedImgSrc} 
                        profilePhoto={profileState.data.photo} 
                    />
                </Box>
                </Box>
            </PageCard>

            {/* Crop Dialog */}
            <AppDialog
                open={showCropDialog}
                onClose={handleCropCancel}
                maxWidth="md"
                busy={isProcessing}
                title={
                    <Box sx={{ display: 'flex', alignItems: 'center', gap: 1 }}>
                        <CropIcon />
                        <Typography component="span">Crop Your Photo</Typography>
                    </Box>
                }
                actions={
                    <>
                        <Button onClick={handleCropCancel} disabled={isProcessing} color="inherit">
                            Cancel
                        </Button>
                        <Button
                            onClick={handleCropComplete}
                            variant="contained"
                            disabled={isProcessing || !completedCrop}
                        >
                            {isProcessing ? "Uploading..." : "Crop & Upload"}
                        </Button>
                    </>
                }
            >
                <Box sx={{ padding: 2 }}>
                    <Typography variant="body2" color="text.secondary" sx={{ mb: 2 }}>
                        Drag to adjust the crop area. Your photo will be automatically uploaded after cropping.
                    </Typography>
                    {imgSrc && (
                        <ReactCrop
                            crop={crop}
                            onChange={(_, percentCrop) => setCrop(percentCrop)}
                            onComplete={(c) => setCompletedCrop(c)}
                            aspect={1} // Square aspect ratio
                            style={{ maxHeight: '400px' }}
                        >
                            {/* eslint-disable-next-line @next/next/no-img-element */}
                            <img
                                ref={imgRef}
                                alt="Crop preview"
                                src={imgSrc}
                                style={{ maxHeight: '400px', maxWidth: '100%' }}
                                onLoad={onImageLoad}
                            />
                        </ReactCrop>
                    )}
                </Box>
            </AppDialog>
        </>
    );
};
